function formatText(result) {
  const lines = [
    `Project: ${result.name} v${result.version}`,
    `Dependencies (${result.deps.length}): ${result.deps.join(', ')}`,
    `Dev dependencies (${result.devDeps.length}): ${result.devDeps.join(', ')}`,
  ];
  return lines.join('\n');
}

module.exports = { formatText };
EOF
